$enable-negative-margins: true !default;
$enable-container-classes: true !default;
$enable-dynamic-values: true !default;
$enable-css-functions: true !default;

// Variables globales
$utility-map: () !default;
$jit-utilities: () !default;

// Échelle d'espacement
$spacer: 1rem !default;
$spacers: (
  0: 0,
  1: $spacer * 0.25,
  2: $spacer * 0.5,
  3: $spacer,
  4: $spacer * 1.5,
  5: $spacer * 3,
  6: $spacer * 4.5,
  7: $spacer * 6,
  8: $spacer * 9
) !default;

// Couleurs du thème
$theme-colors: (
  primary: #0d6efd,
  secondary: #6c757d,
  success: #198754,
  danger: #dc3545,
  warning: #ffc107,
  info: #0dcaf0,
