    @if $key != 0 {
      $negative-spacers: map-merge($negative-spacers, ("n" + $key: -$value));
    }
  }
}

// 7. Système JIT amélioré avec support CSS Functions
// =============================================
@function get-properties-for-prefix($prefix) {
  $property-map: (
    "p": (padding: null),
    "px": (padding-left: null, padding-right: null),
    "py": (padding-top: null, padding-bottom: null),
    "pt": (padding-top: null),
    "pr": (padding-right: null),
    "pb": (padding-bottom: null),
    "pl": (padding-left: null),
    "pe": (padding-right: null),
    "ps": (padding-left: null),
    "m": (margin: null),
    "mx": (margin-left: null, margin-right: null),
    "my": (margin-top: null, margin-bottom: null),
    "mt": (margin-top: null),
    "mr": (margin-right: null),
    "mb": (margin-bottom: null),
    "ml": (margin-left: null),
    "me": (margin-right: null),
    "ms": (margin-left: null),
    "w": (width: null),
    "h": (height: null),
    "min-w": (min-width: null),
    "min-h": (min-height: null),
    "max-w": (max-width: null),
    "max-h": (max-height: null),
    "rounded": (border-radius: null),
    "text": (font-size: null),
    "leading": (line-height: null),
    "tracking": (letter-spacing: null),
    "top": (top: null),
    "right": (right: null),
    "bottom": (bottom: null),
    "left": (left: null),
    "inset": (top: null, right: null, bottom: null, left: null),
    "z": (z-index: null),
    "opacity": (opacity: null),
    "gap": (gap: null),
    "gap-x": (column-gap: null),
    "gap-y": (row-gap: null)
  );
