}

@mixin jit-utility($class, $properties, $breakpoint: "") {
  $full-class: if($breakpoint == "", $class, "#{$breakpoint}-#{$class}");

  @if not map-has-key($jit-utilities, $full-class) {
    $jit-utilities: map-merge($jit-utilities, ($full-class: true)) !global;

    @if $breakpoint == "" {
      .#{$class} {
        @each $prop, $val in $properties {
          #{$prop}: $val if($enable-important-utilities, !important, null);
        }
      }
    } @else {
      @include media-breakpoint-up($breakpoint) {
        .#{$breakpoint}\:#{$class} {
          @each $prop, $val in $properties {
            #{$prop}: $val if($enable-important-utilities, !important, null);
          }
        }
      }
    }
  }
}

@function parse-responsive-class($class) {
  $breakpoint: "";
  $clean-class: $class;

  @each $bp in map-keys($grid-breakpoints) {
    @if $bp != "xs" and string.index($class, "#{$bp}:") == 1 {
      $breakpoint: $bp;
      $clean-class: string.slice($class, string.length($bp) + 2);
    }
  }
  @return (breakpoint: $breakpoint, class: $clean-class);
}

@mixin jit-apply($utilities...) {
  @each $util in $utilities {
    $parsed: parse-responsive-class($util);
    $breakpoint: map-get($parsed, breakpoint);
    $clean-util: map-get($parsed, class);

    @if string.index($clean-util, "-[") {
      $prefix: string.slice($clean-util, 1, string.index($clean-util, "-[") - 1);
      $dynamic-value: extract-dynamic-value($clean-util);
      $properties: get-properties-for-prefix($prefix);

      @if $properties {
        @if $breakpoint == "" {
          @each $prop, $val in $properties {
            #{$prop}: $dynamic-value if($enable-important-utilities, !important, null);
          }
        } @else {
          @include media-breakpoint-up($breakpoint) {
            @each $prop, $val in $properties {
              #{$prop}: $dynamic-value if($enable-important-utilities, !important, null);
            }
          }
        }

        // Generate safe class name for CSS
        $raw-value: string.slice($clean-util, string.index($clean-util, "[") + 1, string.index($clean-util, "]") - 1);
        $safe-name: safe-class-name($raw-value);
        $class-name: "#{$prefix}-#{$safe-name}";

        $jit-properties: ();
        @each $prop, $val in $properties {
          $jit-properties: map-merge($jit-properties, ($prop: $dynamic-value));
        }

        @include jit-utility($class-name, $jit-properties, $breakpoint);
      } @else {
        @warn "Préfixe d'utilitaire non reconnu: #{$prefix} dans #{$clean-util}";
      }
    } @else {
      @include apply($util);
    }
  }
}

